import 'package:sqflite/sqflite.dart';

class TransactionRepository {
  final Database _db;
  TransactionRepository(this._db);

  Future<void> saveTransaction(Transaction tx) async {
    await _db.transaction((txn) async {
      // Insert main transaction row
      await txn.insert('transactions', tx.toMap());

      // Deduct inventory stock for each item
      for (var item in tx.items) {
        await txn.rawUpdate(
          'UPDATE products SET stock = stock - ? WHERE id = ?',
          [item.quantity, item.productId],
        );
      }
    });
  }
}

// REST API handler snippet saving watch log telemetry
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_PUBLISHABLE_KEY!);

export default async function handler(req: Request, res: Response) {
  const syncId = req.headers['x-sync-id'];
  const { data } = req.body;

  // Perform upsert of watch logs to Supabase database
  const { error } = await supabase
    .from('sync_storage')
    .upsert({ id: syncId, data: data, updated_at: new Date().toISOString() });

  if (error) return res.status(500).json({ error: error.message });
  return res.status(200).json({ success: true });
}

btn.setOnTouchListener { v, event ->
    val params = overlayParams ?: return@setOnTouchListener false
    when (event.action) {
        MotionEvent.ACTION_DOWN -> {
            initialRawX = event.rawX; initialRawY = event.rawY
            initialX = params.x; initialY = params.y
            true
        }
        MotionEvent.ACTION_MOVE -> {
            if (currentState == OverlayState.IDLE) {
                val deltaX = event.rawX - initialRawX
                val deltaY = event.rawY - initialRawY
                params.x = initialX + deltaX.toInt()
                params.y = initialY + deltaY.toInt()
                windowManager.updateViewLayout(root, params)
            }
            true
        }
        MotionEvent.ACTION_UP -> {
            val distance = Math.hypot((event.rawX - initialRawX).toDouble(), (event.rawY - initialRawY).toDouble())
            if (distance < 10.0) {
                v.performClick()
                updateState(if (currentState == OverlayState.IDLE) OverlayState.LOCKED else OverlayState.IDLE)
            }
            true
        }
        else -> false
    }
}
